import type { JSX } from 'react';
import type { LlmProvider } from '@meebox/shared';

// LLM provider 品牌图标。OpenAI / Anthropic 用官方几何标记；其余几家无干净的
// 官方单色 SVG 资源，按品牌意象手绘为简洁可辨的彩色图标（鲸鱼 / 羊驼 / 云 /
// 火山 / 通用 API 字形）。后续如放入正式 logo 资源，替换这里对应分支即可。

